import React, { useState, useEffect } from 'react';
import { getMyProperties } from '../../services/dataService';
import { getConstructionUpdates } from '../../services/dataService';
import { formatDate } from '../../utils/helpers';
import StatusBadge from '../../components/common/StatusBadge';
import LoadingSpinner from '../../components/common/LoadingSpinner';

const CustomerConstruction = () => {
  const [properties, setProperties] = useState([]);
  const [selected, setSelected] = useState(null);
  const [updates, setUpdates] = useState([]);
  const [loading, setLoading] = useState(true);
  const [loadingUpdates, setLoadingUpdates] = useState(false);

  useEffect(() => {
    const fetch = async () => {
      try {
        const res = await getMyProperties();
        setProperties(res.data.data);
        if (res.data.data.length > 0) {
          setSelected(res.data.data[0]._id);
          await fetchUpdates(res.data.data[0]._id);
        }
      } catch (err) { console.error(err); }
      finally { setLoading(false); }
    };
    fetch();
  }, []);

  const fetchUpdates = async (propId) => {
    setLoadingUpdates(true);
    try {
      const res = await getConstructionUpdates(propId);
      setUpdates(res.data.data || []);
    } catch { setUpdates([]); }
    finally { setLoadingUpdates(false); }
  };

  const handleSelect = (propId) => {
    setSelected(propId);
    fetchUpdates(propId);
  };

  const selectedProp = properties.find(p => p._id === selected);

  if (loading) return <LoadingSpinner />;

  return (
    <div>
      <div className="page-header"><h1>Construction Status</h1></div>

      {properties.length === 0 ? (
        <div className="empty-state"><p>No properties to track</p></div>
      ) : (
        <>
          <div className="filters-bar">
            {properties.map(p => (
              <button key={p._id} className={`btn btn-sm ${selected === p._id ? 'btn-primary' : 'btn-outline'}`} onClick={() => handleSelect(p._id)}>
                {p.title}
              </button>
            ))}
          </div>

          {selectedProp && (
            <div className="card" style={{ marginBottom: '24px' }}>
              <h3>{selectedProp.title}</h3>
              <div style={{ display: 'flex', gap: '24px', alignItems: 'center' }}>
                <div><span className="detail-label">Status</span><StatusBadge status={selectedProp.constructionStatus} /></div>
                <div style={{ flex: 1 }}>
                  <div className="progress-bar"><div className="progress-fill" style={{ width: `${selectedProp.constructionPercentage || 0}%` }}></div></div>
                  <small>{selectedProp.constructionPercentage || 0}% Complete</small>
                </div>
              </div>
            </div>
          )}

          {loadingUpdates ? <LoadingSpinner /> : (
            <div className="card">
              <h3>Construction Timeline</h3>
              {updates.length === 0 ? <p>No updates yet</p> : (
                <div className="timeline">
                  {updates.map(u => (
                    <div key={u._id} className="timeline-item">
                      <div className="timeline-date">{formatDate(u.createdAt)}</div>
                      <div className="timeline-content">
                        <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                          <StatusBadge status={u.status} />
                          <span>{u.percentage}% complete</span>
                        </div>
                        {u.notes && <p style={{ marginTop: '4px' }}>{u.notes}</p>}
                        {u.images && u.images.length > 0 && (
                          <div style={{ display: 'flex', gap: '8px', marginTop: '8px', flexWrap: 'wrap' }}>
                            {u.images.map((img, i) => (
                              <img key={i} src={`http://localhost:5000${img}`} alt="Update" style={{ width: '120px', height: '90px', objectFit: 'cover', borderRadius: '4px' }} />
                            ))}
                          </div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </>
      )}
    </div>
  );
};

export default CustomerConstruction;
